Style 2

The plotThe code











tooltip_css &lt;- "
background-color: #1f2937;
color: #ffffff;
padding: 8px 12px;
border-radius: 6px;
font-size: 14px;
font-weight: bold;
box-shadow: 0px 2px 8px rgba(0,0,0,0.3);
" #&lt;&lt;

p &lt;- ggplot(data=exam_data, 
       aes(x = MATHS)) +
  geom_dotplot_interactive(              
    aes(tooltip = ID),                   
    stackgroups = TRUE,                  
    binwidth = 1,                        
    method = "histodot") +               
  scale_y_continuous(NULL,               
                     breaks = NULL)
girafe(                                  
  ggobj = p,                             
  width_svg = 6,                         
  height_svg = 6*0.618,
  options = list(    #&lt;&lt;
    opts_tooltip(    #&lt;&lt;
      css = tooltip_css)) #&lt;&lt;
)

